<div class="page-header"><div><h2 class="page-title">Modifier l'article</h2><p class="page-meta">Mettez a jour le contenu et le statut.</p></div></div><form action="/admin/articles/<?=(int)$post['id']?>"class="card form-card"method="post"><div class="form-field"><label for="title">Titre</label> <input class="form-input"id="title"name="title"required value="<?=htmlspecialchars($post['title'])?>"></div><div class="form-field"><label for="content">Contenu</label> <textarea class="form-textarea"id="content"name="content"required rows="8"><?=htmlspecialchars($post['content'])?></textarea></div><div class="form-field"><label for="status">Statut</label> <select class="form-select"id="status"name="status"><option value="draft"<?=$post['status']==='draft'?'selected':''?>>Brouillon</option><option value="published"<?=$post['status']==='published'?'selected':''?>>Publie</option></select></div><button class="btn btn-primary"type="submit">Mettre a jour</button></form>